import { useState } from "react";

const initialTasks = [
  { id: "a1", text: "Ship the release" },
  { id: "b2", text: "Fix the flaky test" },
  { id: "c3", text: "Review the RFC" },
];

export default function TaskList() {
  const [tasks, setTasks] = useState(initialTasks);

  function moveToTop(index) {
    setTasks((prev) => [prev[index], ...prev.filter((_, i) => i !== index)]);
  }

  return (
    <ul>
      {tasks.map((task, index) => (
        <li key={index}>
          <input type="checkbox" aria-label={`done: ${task.text}`} />
          <span>{task.text}</span>
          <button onClick={() => moveToTop(index)}>Pin</button>
        </li>
      ))}
    </ul>
  );
}

